const path = require("node:path");
const { pathToFileURL } = require("node:url");

class ESLint {
  constructor(options) {
    this.cwd = options.cwd;
    this.overrideConfigFile = options.overrideConfigFile;
  }

  async isPathIgnored() {
    return false;
  }

  async calculateConfigForFile(filePath) {
    const config = (await import(pathToFileURL(this.overrideConfigFile).href)).default;
    const relPath = path.relative(this.cwd, filePath).replaceAll(path.sep, "/");
    const key = relPath.endsWith(".js")
      ? "js"
      : relPath.includes(".test.") || relPath.includes(".spec.")
        ? "test"
        : relPath.endsWith(".tsx")
          ? "tsx"
          : "ts";
    return config[key] ?? config.ts;
  }
}

module.exports = { ESLint };
